-- ===========================================
-- Workflow enhancement tables - PostgreSQL HASH partitioned version
-- All IDs generated by application-layer SnowflakeIdGenerator
-- All tables partitioned by process_instance_id with 16 partitions
-- PK: (id, process_instance_id)
-- ===========================================

-- ===========================================
-- Supervision instance table
-- ===========================================
CREATE TABLE se_supervision_instance (
  id bigint NOT NULL,
  gmt_create timestamp(6) NOT NULL,
  gmt_modified timestamp(6) NOT NULL,
  process_instance_id bigint NOT NULL,
  task_instance_id bigint NOT NULL,
  supervisor_user_id varchar(255) NOT NULL,
  supervision_reason varchar(500),
  supervision_type varchar(64) NOT NULL,
  status varchar(64) NOT NULL,
  close_time timestamp(6),
  tenant_id varchar(64),
  PRIMARY KEY (id, process_instance_id)
) PARTITION BY HASH (process_instance_id);

COMMENT ON TABLE se_supervision_instance IS 'Supervision instance table';
COMMENT ON COLUMN se_supervision_instance.supervision_type IS 'urge/track/remind';
COMMENT ON COLUMN se_supervision_instance.status IS 'active/closed';

CREATE INDEX idx_supervision_task_status_tenant
  ON se_supervision_instance (task_instance_id, status, tenant_id);
CREATE INDEX idx_supervision_supervisor_tenant
  ON se_supervision_instance (supervisor_user_id, tenant_id);
CREATE INDEX idx_supervision_process_instance_id
  ON se_supervision_instance (process_instance_id);

CREATE TABLE se_supervision_instance_p00 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 0);
CREATE TABLE se_supervision_instance_p01 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 1);
CREATE TABLE se_supervision_instance_p02 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 2);
CREATE TABLE se_supervision_instance_p03 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 3);
CREATE TABLE se_supervision_instance_p04 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 4);
CREATE TABLE se_supervision_instance_p05 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 5);
CREATE TABLE se_supervision_instance_p06 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 6);
CREATE TABLE se_supervision_instance_p07 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 7);
CREATE TABLE se_supervision_instance_p08 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 8);
CREATE TABLE se_supervision_instance_p09 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 9);
CREATE TABLE se_supervision_instance_p10 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 10);
CREATE TABLE se_supervision_instance_p11 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 11);
CREATE TABLE se_supervision_instance_p12 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 12);
CREATE TABLE se_supervision_instance_p13 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 13);
CREATE TABLE se_supervision_instance_p14 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 14);
CREATE TABLE se_supervision_instance_p15 PARTITION OF se_supervision_instance FOR VALUES WITH (MODULUS 16, REMAINDER 15);

-- ===========================================
-- Notification instance table
-- ===========================================
CREATE TABLE se_notification_instance (
  id bigint NOT NULL,
  gmt_create timestamp(6) NOT NULL,
  gmt_modified timestamp(6) NOT NULL,
  process_instance_id bigint NOT NULL,
  task_instance_id bigint,
  sender_user_id varchar(255) NOT NULL,
  receiver_user_id varchar(255) NOT NULL,
  notification_type varchar(64) NOT NULL,
  title varchar(255),
  content varchar(1000),
  read_status varchar(64) NOT NULL DEFAULT 'unread',
  read_time timestamp(6),
  tenant_id varchar(64),
  PRIMARY KEY (id, process_instance_id)
) PARTITION BY HASH (process_instance_id);

COMMENT ON TABLE se_notification_instance IS 'Notification instance table';
COMMENT ON COLUMN se_notification_instance.notification_type IS 'cc/inform';
COMMENT ON COLUMN se_notification_instance.read_status IS 'unread/read';

CREATE INDEX idx_notification_receiver_read_tenant
  ON se_notification_instance (receiver_user_id, read_status, tenant_id);
CREATE INDEX idx_notification_sender_tenant
  ON se_notification_instance (sender_user_id, tenant_id);
CREATE INDEX idx_notification_process_instance_id
  ON se_notification_instance (process_instance_id);
CREATE INDEX idx_notification_task_instance_id
  ON se_notification_instance (task_instance_id);

CREATE TABLE se_notification_instance_p00 PARTITION OF se_notification_instance FOR VALUES WITH (MODULUS 16, REMAINDER 0);
