-- ===========================================
-- Task transfer record table
-- ===========================================
CREATE TABLE se_task_transfer_record (
  id bigint NOT NULL,
  gmt_create timestamp(6) NOT NULL,
  gmt_modified timestamp(6) NOT NULL,
  task_instance_id bigint NOT NULL,
  process_instance_id bigint NOT NULL,
  from_user_id varchar(255) NOT NULL,
  to_user_id varchar(255) NOT NULL,
  transfer_reason varchar(500),
  deadline timestamp(6),
  tenant_id varchar(64),
  PRIMARY KEY (id, process_instance_id)
) PARTITION BY HASH (process_instance_id);

COMMENT ON TABLE se_task_transfer_record IS 'Task transfer record table';

CREATE INDEX idx_task_transfer_task_tenant
