-- ===========================================
-- Assignee operation record table
-- ===========================================
CREATE TABLE se_assignee_operation_record (
  id bigint NOT NULL,
  gmt_create timestamp(6) NOT NULL,
  gmt_modified timestamp(6) NOT NULL,
  task_instance_id bigint NOT NULL,
  process_instance_id bigint NOT NULL,
  operation_type varchar(64) NOT NULL,
  operator_user_id varchar(255) NOT NULL,
  target_user_id varchar(255) NOT NULL,
  operation_reason varchar(500),
  tenant_id varchar(64),
  PRIMARY KEY (id, process_instance_id)
) PARTITION BY HASH (process_instance_id);

COMMENT ON TABLE se_assignee_operation_record IS 'Assignee operation record table';
COMMENT ON COLUMN se_assignee_operation_record.operation_type IS 'add_assignee/remove_assignee';

